INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027b17e3c98b094176592f', '40年的酒店，外观很久。
里面大气，设施房间一流。
服务更是很棒，老钱风的高水准。
特别是行政酒廊，服务热情主动，谢谢@Kitty。', '["https://dimg04.c-ctrip.com/images/0230d12000f23lxh414B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000f23lvp965F6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-09', '花园大床房', '大床房', '商务出差', 66, 0, 1, 7, '["房间设施","前台服务","餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施'),
('68027b17e3c98b0941765930', '广州美到可以封神的酒店！
艺术，文化，自然和美食，均可在此领略。', '["https://dimg04.c-ctrip.com/images/0236m12000g0lptfvFD42_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235v12000g0ln1cfAD2E_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232z12000g0lrfry9EB8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236e12000g0lrxukF730_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235p12000g0lqtgd4E48_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-10-06', '花园大床房', '大床房', '家庭亲子', 32, 0, 16, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b17e3c98b0941765931', '酒店位置就在地铁口附近，出行方便，大堂非常漂亮，很多外宾住在这里，工作人员也有很多是老外，中文很英文都很好，服务态度也非常好', '["https://dimg04.c-ctrip.com/images/0232r12000f45b68cBF4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000f458vqyF22F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000f45f6zrF33F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-14', '花园双床房', '双床房', '家庭亲子', 62, 0, 2, 7, '["交通便利性","前台服务"]'::jsonb, '交通便利性', '前台服务', NULL),
('68027b17e3c98b0941765932', '服务非常周到、环境优美，还给免费升级了行政套房、赠送了两张早餐卷。', '["https://dimg04.c-ctrip.com/images/0233512000fzaqmmk2849_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000fzalek0E97E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000fza7wboBDF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000fzanhpl43DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000fzapntiAC8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-04', '红棉大床套房', '套房', '家庭亲子', 33, 0, 7, 7, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027b17e3c98b0941765933', '设施：卫浴设施有点老旧，尤其是卫生间，冲水的时候总觉得水阀要坏了。

卫生：整体还不错
环境：很好，饭后在酒店里逛逛，当散步 
服务：服务员都很好，很细致很热心，看起来培训到位。', '["https://dimg04.c-ctrip.com/images/0233j12000enzmq5fB1FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000enzn2x155B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000enzkmkd3904_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000enzrf9x7CA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000enzmlzkE91B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000enzuwml1B32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.1, 4, '2024-07-03', '粤韵双床套房', '套房', '朋友出游', 89, 0, 13, 7, '["房间设施","卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL),
('68027b17e3c98b0941765934', '酒店大堂奢华，房间设施就过得去，房间略显成就，送下午茶点心', '["https://dimg04.c-ctrip.com/images/0233812000gen57iiFD7D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000genhiujED19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000genhiulB3CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000genfsy3AD0E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000gemryx2052E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000gengrjm2D4F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-31', '花园双床房', '双床房', '其他', 29, 0, 47, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027b17e3c98b0941765935', '这次的酒店套餐活动非常好??房间干净整洁，早餐也很好吃，行政酒廊欢乐时光小食丰富，Carrie、Berlye服务很好', '["https://dimg04.c-ctrip.com/images/0233h12000f6ua8ru25AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000f6u0qro9102_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000f6uel8oC72A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-20', '花园大床房', '大床房', '情侣出游', 58, 0, 3, 7, '["餐饮设施","卫生状况","客房服务"]'::jsonb, '餐饮设施', '卫生状况', '客房服务'),
('68027b24e3c98b0941765936', '周末带小朋友玩，第二次来花园酒店，服务一如既往的好，有花园小桥流水，有丰盛的自助餐，空中旋转餐厅，还有沉淀历史文化的博物馆，', '["https://dimg04.c-ctrip.com/images/0232c12000fxj111rE900_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000fxixcb12B13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000fxi75xg52BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000fxj4rk58623_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000fxiv6qy762D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000fxiga4a248F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-03', '花园大床房', '大床房', '家庭亲子', 62, 0, 18, 8, '["餐饮设施","整体满意度","公共设施"]'::jsonb, '餐饮设施', '整体满意度', '公共设施'),
('68027b24e3c98b0941765937', '前台服务很热情，大堂造型很顶，入住时才知道花园酒店是中国三家白金五星酒店之一，还有个酒店博物馆。整体感觉不错。', '["https://dimg04.c-ctrip.com/images/0233r224x8w26llli14ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02323224x8w28gvji3736_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q224x8w29k1v127E4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-24', '花园双床房', '双床房', '家庭亲子', 55, 0, 1, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b24e3c98b0941765938', '前台生小姐妹态度很好，帮我升级了套房，送了行政下午茶 可惜只送了我这个岭客汇会员，总体是一次很不错的旅行。', '["https://dimg04.c-ctrip.com/images/0201z12000flam6tr9FD2_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236912000flal6hyC2BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000flal6i0B70D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000fl9pcno5662_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000fla5zfb3256_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000flafgeg0140_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000flakdiyCF07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-16', '花园双床房', '双床房', '情侣出游', 53, 0, 3, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b24e3c98b0941765939', '老牌五星级酒店，细节很有特色和文化底蕴，早餐在一楼和三十楼都可以，菜品很丰富，三十楼的旋转餐厅可360度观景，用下午茶时30楼行政酒廊的印度小姐姐carrie中文流利、热情大方，第二天早餐后还收到了全英文的祝福小卡片，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0233e12000eny75s57C84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000enxxek479CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-03', '红棉大床套房', '套房', '其他', 116, 0, 2, 9, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b24e3c98b094176593a', '老牌五星，环境服务一流。晚餐都在30楼行政酒廊解决，工作人员都很热情，就是出餐的种类可以再丰富一点就好了。', '["https://dimg04.c-ctrip.com/images/0231w12000f8y266z175A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000f8yexjoFF14_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000f8y3fnvCD26_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-25', '花园双床房', '双床房', '家庭亲子', 53, 0, 3, 7, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b24e3c98b094176593b', '入住广州花园酒店是我在广东住的最满意的酒店，一进大堂，富丽堂皇！虽然是老五星，很有年代感，服务却很到位！后花园真的漂亮，小朋友特别喜欢，喷泉瀑布园林花草！特别是前台的小洪美女细心的在身份证上看到当天的生日，贴心的为我们免费升级了房间，让我们在酒店过了一个难忘的生日！真心感谢！还有迎宾的李雯美女，送了礼物给了我家的小朋友，谢谢你们！', '["https://dimg04.c-ctrip.com/images/0235d12000j9rs8b10667_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000j9s1dtq13B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000j9ray9lCE58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000j9s1bp4DABB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000j9ripa3934F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-23', '花园双床房', '双床房', '家庭亲子', 166, 0, 5, 9, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68027b24e3c98b094176593c', '酒店不错！', '["https://dimg04.c-ctrip.com/images/0233212000gzwyoi1EDA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000gzxoqqg018E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000gzxgkij341A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-12-02', '花园大床房', '大床房', '家庭亲子', 5, 0, 14, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b24e3c98b094176593d', '花园酒店，名副其实！环境真的很美，酒店的每处的花艺设计都非常高级！尤其是瀑布餐厅，只能用哇塞来形容了??????拍照巨出片！
再来夸一下服务，从到酒店大门下车，从迎宾开始的每一位工作人员都很有耐心，满脸笑容！真的让我体会到了宾至如归的感觉！因为是zijiz人带着1岁多的宝宝，有的时候来不及照看宝宝的时候，大厅里的工作人员都会帮忙照顾，非常贴心！
虽然花园酒店是老牌五星酒店，但是房间设施还是一样很好！唯一的建议就是希望贵酒店能够提供儿童围栏就更加完美了！', '["https://dimg04.c-ctrip.com/images/0230s12000ergsov65807_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000ergp7q8D3CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000ergpnpb9297_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000ergsb4s919A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000ero0gc8F764_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000erntfco2AC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-13', '花园大床房', '大床房', '家庭亲子', 228, 0, 2, 9, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027b24e3c98b094176593e', '带爸妈一起出游，入住3晚的红棉套房，非常好的体验，前台的工作人员Winne Wei热情负责。

酒店保养了不错，比较新。打车去各景点都比较近，餐饮配套齐全，这点特别方便。留了一点小遗憾，来不及去打卡瀑布餐厅下午茶。', '["https://dimg04.c-ctrip.com/images/0234u12000fyatoe0AF18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000fy9iizb4969_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000fya7brhCBE6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000fy94hl8A6FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000fy9g4li13CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-03', '花园双床房', '双床房', '家庭亲子', 107, 0, 2, 7, '["前台服务","周边配套","交通便利性"]'::jsonb, '前台服务', '周边配套', '交通便利性'),
('68027b24e3c98b094176593f', '白金五星，确实很棒，虽然年份有点久，但是各方面服务都很好，很多航空公司机组人员都住这里
泳池游泳，服务生很快就送上清凉饮品，真棒', '["https://dimg04.c-ctrip.com/images/0232112000f86vhr0E3FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000f87d537AD99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000f878gzf7204_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000f87dmk86180_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-23', '花园双床房', '双床房', '家庭亲子', 64, 0, 16, 7, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027b2fe3c98b0941765940', '中秋期间入住，十分令人惊喜的一家酒店，从前台Winnie的接待开始，就感受到了酒店热情热心的高水准服务。客服服务员的整理和打扫非常细致，早上刷牙不小心打碎了漱口杯、立即来帮忙现场处理。临走还收到了楼层引导员小李的祝福和小礼物。餐厅服务体验了两天的下午茶歇，行政酒廊以及早餐，一楼的服务较顶楼略逊色一点点，但早餐的选择和品质都很不错，完全弥补了服务上的不足。顶楼的服务员都很漂亮温柔，服务也很细致
真的很推荐大家入住噢！', '["https://dimg04.c-ctrip.com/images/0236112000fl7p8464A9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000fl7d2qfC32E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000fl7xb894614_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-16', '花园大床房', '大床房', '情侣出游', 209, 0, 2, 9, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68027b2fe3c98b0941765941', '房间安排的非常好，早餐也很丰富，酒店内也是有可参观和玩的地方，附近有名的餐厅蛮多，不过酒店内的餐厅也很好。', '["https://dimg04.c-ctrip.com/images/0236k12000gnyf0ji1DCF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000gnyfuldFD93_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000gnyf0jm6415_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-13', '花园双床房', '双床房', '商务出差', 53, 0, 37, 6, '["餐饮设施","周边配套","整体满意度"]'::jsonb, '餐饮设施', '周边配套', '整体满意度'),
('68027b2fe3c98b0941765942', '很不错的酒店，性价比很高。工作人员很热情，我们一家三口出行，还特意免费升级了房间。贴心的给小朋友准备了儿童拖鞋，还多给了饮用水。', '["https://dimg04.c-ctrip.com/images/0233s12000ezolm5uB349_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000ezoh3awE614_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000ezobrphB46D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000ezoc9iuA6F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000ezobkws6416_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-03', '花园双床房', '双床房', '家庭亲子', 64, 0, 11, 8, '["性价比","前台服务","整体满意度"]'::jsonb, '性价比', '前台服务', '整体满意度'),
('68027b2fe3c98b0941765943', '环境很一般', '["https://dimg04.c-ctrip.com/images/0230h12000gwzct8rDB8E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.8, 2, '2024-11-28', '花园大床房', '大床房', '商务出差', 5, 0, 12, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b2fe3c98b0941765944', '不愧是白金五星，不愧是花园酒店，服务很好，隔音也很好，比现在的新酒店真的不知道强多少，感谢ceclia，看到我们带娃帮忙协调房间，酒店餐厅也都很好吃，第二天花园的桂花太香了，真的很推荐', '["https://dimg04.c-ctrip.com/images/0232p12000hoevwri0CE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000hoeqqt78FA8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000hoevwy4347D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000hoewoux5CBF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-01-09', '花园双床房', '双床房', '家庭亲子', 92, 0, 10, 8, '["整体满意度","前台服务","安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度'),
('68027b2fe3c98b0941765945', '房间设施非常好??前台服务小哥kasas服务也很周到，后花园很漂亮，大堂非常雅观！', '["https://dimg04.c-ctrip.com/images/0231c12000jkxm4unCE48_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-05', '城央绿意大床房', '大床房', '情侣出游', 41, 0, 2, 6, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68027b2fe3c98b0941765946', '满分好评，感谢Rebecca女士帮我们升级了套房房型，让旅行十分完美！@Rebecca
老牌白金五星酒店，瀑布餐厅超级壮观。
最主要是房间整洁、宽敞，新中式的装修风格给人留下了深刻印象，电动窗帘和中式酒柜的设计也很别出心裁。
最重要的是这个窗边浴缸十分满意了，看着城景泡澡，一种闹中取静，大隐于市的感觉。', '["https://dimg04.c-ctrip.com/images/0234t12000eefthdl004E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000eefxz41BE99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000eefq8ya68A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000eefxeg8B492_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000eefsqvdAF61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000eeg499kD14B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-09', '城央绿意大床房', '大床房', '情侣出游', 152, 0, 6, 9, '["房间设施","整体满意度","景观/朝向"]'::jsonb, '房间设施', '整体满意度', '景观/朝向'),
('68027b2fe3c98b0941765947', '具歴史代表的五星酒店。', '["https://dimg04.c-ctrip.com/images/02344224x8y5kb05n3CFC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-21', '红棉大床套房', '套房', '家庭亲子', 11, 0, 3, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b2fe3c98b0941765948', '房间整洁明亮，温馨舒适。服务热情周到，宾至如归。酒店位置好，出行方便。酒店竟然有瀑布和博物馆，很意外。大堂更是金碧辉煌，服务员还主动帮我们照了相。免费升级了房间和延时退房。体验很好很满意。', '["https://dimg04.c-ctrip.com/images/0235g12000f04jtuw9E0C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000f04620nABE1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000f04k5h94879_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-04', '城央绿意双床房', '双床房', '家庭亲子', 94, 0, 1, 8, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('68027b2fe3c98b0941765949', '来住过很多次了，各种房型都住过，非常舒适。服务很好，有求必应。这个位置去哪儿哪儿也都方便。而且疫情后越来越热闹了，早餐也变得越来越好吃了。', '["https://dimg04.c-ctrip.com/images/02302224x8vptv7va65A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l224x8vptvz0d6B98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d224x8vpttfy9A8DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02314224x8vptv7vbFF2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h224x8vptwci7DB8C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-24', '花园大床房', '大床房', '商务出差', 69, 0, 6, 7, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027b39e3c98b094176594a', '花园酒店就在地铁出口处，出行非常方便，对面就有广州酒家，早午茶味道不错，价格也不贵。酒店的服务人员非常热情，有求必应，以后带家人还会再去哦', '["https://dimg04.c-ctrip.com/images/0235112000ewfk4qbC3EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000ewfo31a31FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000ewfjjbg1D6C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-07-26', '花园大床房', '大床房', '独自旅行', 69, 0, 3, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027b39e3c98b094176594b', '服务很到位，环境很好', '["https://dimg04.c-ctrip.com/images/0232x12000gmcvyk107B7_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-11-11', '红棉大床套房', '套房', '独自旅行', 10, 0, 18, 4, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027b39e3c98b094176594c', '很好，出差广州第二次选择了！酒店很有底蕴，酒店工作人员很礼貌，又给升级了房间，挺好挺好！下次还会选择！', '["https://dimg04.c-ctrip.com/images/0235j12000f6gqslzEEAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000f6gsiis0ED5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000f6gqt61597A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-19', '花园双床房', '双床房', '商务出差', 51, 0, 62, 6, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027b39e3c98b094176594d', '出差多年，五星级酒店也住过很多，第一次特别想写点评给花园酒店，不管是套房旋转餐厅还是服务人员的服务态意识，水准都非常高！景色太棒了(ˉ▽ˉ)??，太适合我们这样出差没时间逛的客人了，酒吧乐队水平也很高，请每位喝了一瓶啤酒，性价比绝高，推荐给朋友100次(‐＾▽＾‐)??', '["https://dimg04.c-ctrip.com/images/0234s12000e8qgpzt9FAC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000e8r02e67F52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000e8r056gED09_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000e8qvne6CF6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000e8qu5hr006F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000e8r05e04F45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000e8qe27v44F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000e8r056iDB19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000e8qnafeFE50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-30', '花园大床房', '大床房', '商务出差', 135, 0, 11, 8, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('68027b39e3c98b094176594e', '这次总共入住4晚，可爱的前厅Virina小姐姐(名字拼写不知道有没有写错)让我们用很优惠的价格升级到粤韵双床房，还送了早餐！
超级棒的入住体验，酒店出门就是地铁去哪都很方便。下次去广州还会选择花园酒店！', '["https://dimg04.c-ctrip.com/images/0233j12000ee05hamE3EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000ee053zjDF7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000ee114zz839B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000edzjjarD7CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000ee0hr03F387_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000ee0kxgeC46C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000ee0c36569B8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-09', '花园双床房', '双床房', '家庭亲子', 101, 0, 8, 8, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027b39e3c98b094176594f', '体验非常好，不愧是老牌五星酒店，打卡过上海花园酒店，慕名来到广州花园酒店。感谢客房部姚师傅，非常细心周到，下次还会去', '["https://dimg04.c-ctrip.com/images/0236o12000hzukicj630C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000hzupp3g77D9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-22', '红棉大床套房', '套房', '家庭亲子', 58, 0, 10, 6, '["整体满意度","客房服务"]'::jsonb, '整体满意度', '客房服务', NULL),
('68027b39e3c98b0941765950', '和同事出差，一如既往的历史的沉淀的稳重的高级感。热情的服务，布置精美的鲜花出其不意的出现在各个角落。健身房环境也很赞完成了一个5公里', '["https://dimg04.c-ctrip.com/images/0230f12000fewetmjA171_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000fewc5761E5A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-05', '花园大床房', '大床房', '商务出差', 66, 0, 23, 7, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027b39e3c98b0941765951', '第一次住花园酒店，设施卫生环境都很好，前台的Viria非常nice，想人所想急人所急，表扬一下，老板该给加薪了。??因为不错的服务又续住了几晚，下次还会再来。', '["https://dimg04.c-ctrip.com/images/0234x12000epphwhr81C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000epprkqx19EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000eppqzyv35D7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-08', '花园双床房', '双床房', '家庭亲子', 79, 0, 5, 7, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027b39e3c98b0941765952', '花园酒店是老牌的五星酒店了，地段就在闹市中心，大堂金碧辉煌，带一个大大的后花园，四楼还有一个酒店博物馆，酒店自带10家餐厅，可以说无敌方便了。30楼的旋转餐厅可以俯瞰360度风景，环境雅致，早餐品种很丰富，下午提供下午茶、五点后还有happy hour，来自印度的Carrie讲得一口流利的中文，笑容甜美，热心帮我们介绍了很多美食，还有美酒、现做的烤饼，还会热情跟小朋友互动，Aimee、Mignon服务效率特别高，还有Lina，都让人感受到宾至如归，一家人都留下难忘的美好回忆，下次还会再来的！', '["https://dimg04.c-ctrip.com/images/0231u12000eeeo6wl33C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000eeep36cF8D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000eeegvxt159D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000eeeojmx8172_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000eeekpz91501_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-09', '花园大床房', '大床房', '家庭亲子', 248, 0, 2, 9, '["餐饮设施","整体满意度","周边配套"]'::jsonb, '餐饮设施', '整体满意度', '周边配套'),
('68027b39e3c98b0941765953', '花园酒店名不虚传！', '["https://dimg04.c-ctrip.com/images/0236c12000gvu4b5s2559_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-26', '红棉双床套房', '套房', '商务出差', 9, 0, 8, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b4ce3c98b0941765954', '一如既往的 喜欢花园酒家 ,每年都会入住的酒店', '["https://dimg04.c-ctrip.com/images/0233g12000g2ql0379123_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000g2qm0ib14D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-10', '花园大床房', '大床房', '商务出差', 23, 0, 9, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b4ce3c98b0941765955', '每次来广州都住这里，传统老钱五星酒店，花园酒店名不虚传，从硬件到服务都很在线。大师贝聿铭设计的作品，如果有空去酒店花园里散散步非常惬意。', '["https://dimg04.c-ctrip.com/images/0235w12000f7e9ld4FB8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000f7eloy1CAC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000f7ebr2wFE67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000f7ei1h4EF7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000f7eg9s04066_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000f7ecjeb503A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000f7ecknn6A72_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-22', '花园大床房', '大床房', '情侣出游', 68, 0, 11, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027b4ce3c98b0941765956', '干净整洁，位置也挺好，去哪儿都方便，后面有个大公园，散步好去处', '["https://dimg04.c-ctrip.com/images/0207312000fox73yk6C5B_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235k12000fox7o798021_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-22', '城央绿意双床房', '双床房', '商务出差', 31, 1, 19, 6, '["卫生状况","交通便利性","周边配套"]'::jsonb, '卫生状况', '交通便利性', '周边配套'),
('68027b4ce3c98b0941765957', '喜欢前台接待Cassie，态度很好没有无烟房还给我升级了。很贴心… 爱了爱了', '["https://dimg04.c-ctrip.com/images/0232312000fferad4BFE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000ffesm094D6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000ffey0yv1810_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-06', '花园大床房', '大床房', '其他', 38, 0, 2, 7, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027b4ce3c98b0941765958', '前台赠送了早餐，行政酒廊Carrie和Cathy，赠送了下午茶，非常周到热情。酒店很有历史韵味，值得打卡', '["https://dimg04.c-ctrip.com/images/0234w12000f3511ed9E2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000f3510r36BC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-11', '城央绿意双床房', '双床房', '家庭亲子', 52, 0, 3, 6, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027b4ce3c98b0941765959', '环境优美没话说真的。每次出差必选花园酒店入住。前台有位叫什么来好像virIioi戴眼镜的小姐姐非常细心温柔可爱型…哈哈我可能打错英文名。不好意思哈。', '["https://dimg04.c-ctrip.com/images/0203i12000eqcc11uB61A_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235j12000eqc1n3p1CEF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000eqbtemoAE88_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-09', '花园大床房', '大床房', '商务出差', 74, 0, 5, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b4ce3c98b094176595a', '房间卫生干净服务很好热情周到，一楼西餐厅也不错就是太多美洲飞洲伊朗等外国人，周边没什么可吃的离地铁比较近出门就是打车也方便门口就有很多', '["https://dimg04.c-ctrip.com/images/0232v12000et5l7wk75E7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000et5ithw9486_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000et5vz277A67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000et5rly436C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000et5qjp1965E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000et5k13q7C84_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-17', '花园双床房', '双床房', '家庭亲子', 67, 0, 8, 6, '["卫生状况","交通便利性","餐饮设施"]'::jsonb, '卫生状况', '交通便利性', '餐饮设施'),
('68027b4ce3c98b094176595b', '强烈推荐花园酒店，在这里度过了非常愉快的时光。本来看了些差评有些犹豫，但酒店就在地铁口，交通方便，而且由于是从天河区换到这边住，来不及再选了，就想先过来看看，事实证明来对了。一进门就被酒店大堂吸引，中西合璧的布置非常漂亮，工作人员很多但井然有序。前台办理入住的viria小姐姐人美心善，专业高效，很快就办好了手续，主动升级了套房，住的非常舒心，还送了行政酒廊的下午茶，非常感谢。一整天一直在下雨，懒得出门，但行政酒廊的食材新鲜，服务超好，也是很好的体验，mignon一直在介绍酒店各个餐厅，推荐各类饮品和餐食，还按照我的要求，特调了一杯很清淡的酒，非常好喝。Carrie是一个印度小姐姐，聊了一会儿weather，aimee和lina也非常热情周到！早餐在旋转餐厅吃的，俯瞰下去景色很美，小哥哥们服务周到。雨停了，去花园转了一圈，步步有景，鱼很漂亮也很肥，很多人拍照。4层的博物馆比想象中大而全，不仅有酒店的历史，也有些广州的历史和酒店行业的发展史。', '["https://dimg04.c-ctrip.com/images/0233v12000ea5scmuD3C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000ea64e5kE23B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000ea613h93442_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000ea61jx8AB55_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-02', '花园大床房', '大床房', '独自旅行', 425, 0, 8, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027b4ce3c98b094176595c', '酒店老牌五星，大厅很大气，房间很好，前台小姐姐ANN免费升级了房间，唯一就是停车场在边上，要走几步。', '["https://dimg04.c-ctrip.com/images/0233e12000f3ka90d3CF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000f3kac4s95E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 50, 0, 10, 6, '["前台服务","公共设施","整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度'),
('68027b4ce3c98b094176595d', '旧地重游『白金五星级酒店』：广州花园酒店，园林的建筑景观，定会让你宾至如归。每次下榻位于闹中取静的市中心——花园酒店，都能给我一种好温馨的感觉。在这里，我遇到了酒店行政酒廊的Carrie姐姐和她的同事Aimee，得知我们是一家人来城央度假为我们的其中一间房间升级为粤韵房和给了我们一家人的行政酒廊使用权。这次的行政酒廊是在30楼，凌旋阁广州最大的旋转餐厅——可容纳两千多人同时进餐的凌旋阁，北眺云山，南望珠水，可以尽览广州的景色。早餐选择丰富且中西结合。同行老人家都不得不赞叹一个字“靓”。用餐过程中行政酒廊的Carrie姐姐会不定时过来询问是否需要帮助，入住期间还去了后花园观赏锦鲤，感觉“老朋友”都被养得胖嘟嘟了。在这里，Carrie姐姐和Aimee的服务很好的诠释了白金五星级酒店的水平。再次感谢您们对我们一家的款待。期待下次再见！', '["https://dimg04.c-ctrip.com/images/0236u12000e2jzvkgF44E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000e2jzyz1585F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000e2jzv2f8EBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000e2k00oiBC72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000e2k007g8E18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000e2k008q7B1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000e2k189z7F8A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000e2k03wk3C0C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000e2k02niD1B2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-19', '红棉双床套房', '套房', '家庭亲子', 369, 1, 3, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027b57e3c98b094176595e', '豪华大气、服务好', '["https://dimg04.c-ctrip.com/images/0230812000gp66ga39036_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000gp5uojjAD74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000gp61pog6A34_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000gp5vbn988A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-11-15', '花园大床房', '大床房', '商务出差', 8, 0, 26, 3, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027b57e3c98b094176595f', '一如既往的好… 房间不错 …服务好…', '["https://dimg04.c-ctrip.com/images/0235t12000h9ifmngF689_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000h9hw6sy7554_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-18', '花园大床房', '大床房', '商务出差', 18, 0, 7, 3, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68027b57e3c98b0941765960', '白金五星级，名副其实。值得再去哦。', '["https://dimg04.c-ctrip.com/images/0233112000gllf7ac2641_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000gll16ih9620_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000gll16ijF963_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-10', '花园大床房', '大床房', '情侣出游', 17, 0, 23, 4, '["整体满意度","性价比"]'::jsonb, '整体满意度', '性价比', NULL)
